  condition_id: string;
  token_id: string;
  outcome: string;
  shares: number;
  cost_usd: number;
  avg_entry_price: number;
  opened_at_ts: number;
  closed_at_ts?: number;
  is_open: boolean;
  realized_pnl?: number;
  exit_reason?: string;
}

